  class EventBus {
    constructor(){ this.map = new Map(); }
    on(type, fn){ if(!this.map.has(type)) this.map.set(type,new Set()); this.map.get(type).add(fn); return () => this.off(type,fn); }
    off(type, fn){ const set=this.map.get(type); if(set) set.delete(fn); }
    emit(type, payload){ const set=this.map.get(type); if(set) for(const fn of [...set]) { try{ fn(payload); } catch(e){ console.warn('[VCC] listener failed', type, e); } } }
  }
  class Toasts {
    constructor(root){ this.root=root; this.stack=document.createElement('div'); this.stack.className='vcc-toast-stack'; root.appendChild(this.stack); }
    show(title,msg='',ms=4200){ const el=document.createElement('div'); el.className='vcc-toast'; el.innerHTML=`<strong>${escapeHTML(title)}</strong>${msg?`<div>${escapeHTML(msg)}</div>`:''}`; this.stack.appendChild(el); setTimeout(()=>{ el.style.opacity='0'; el.style.transform='translateY(8px)'; setTimeout(()=>el.remove(),220); },ms); }
  }
