    render(){ const q=this.input.value.toLowerCase().trim(); const list=this.commands.filter(c=>!q||c.name.toLowerCase().includes(q)||c.desc.toLowerCase().includes(q)).slice(0,40); this.list.innerHTML=''; for(const c of list){ const b=document.createElement('button'); b.className='vcc-button vcc-command-item'; b.innerHTML=`<strong>${escapeHTML(c.name)}</strong><br><small>${escapeHTML(c.desc)}</small>`; b.addEventListener('click',()=>{ this.close(); c.run(); }); this.list.appendChild(b); } }
