  function currentRunSummary(game){ const p=game&&game.player; return { version:VERSION, state:game?game.state:'unknown', time:fmtTime(game?game.gameTime:0), wave:game?game.wave||1:1, kills:p?p.totalKills||0:0, level:p?p.level||1:1, hp:p?`${Math.ceil(p.hp)}/${Math.ceil(p.maxHp)}`:'—', gold:game&&game.meta?game.meta.totalGold:readMetaGold(), url:location.href }; }
  function asShareText(summary){ return `VOIDRUN ${summary.version} — ${summary.time} | Wave ${summary.wave} | Level ${summary.level} | Kills ${summary.kills} | HP ${summary.hp} | Gold ${summary.gold}`; }
  function exportSaves(){ const out={ exportedAt:new Date().toISOString(), localStorage:{} }; for(let i=0;i<localStorage.length;i++){ const k=localStorage.key(i); if(k&&k.includes('voidrun')) out.localStorage[k]=localStorage.getItem(k); } return JSON.stringify(out,null,2); }
