  function dailyDirective(){ const d=new Date(); const seed=Number(`${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}`); const a=DAILY_DIRECTIVES[seed%DAILY_DIRECTIVES.length]; const b=DAILY_DIRECTIVES[(seed*7+13)%DAILY_DIRECTIVES.length]; const c=DAILY_DIRECTIVES[(seed*17+29)%DAILY_DIRECTIVES.length]; return { seed, directives:[a,b,c] }; }
